1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const BLOCK_OF_3_PRICE = 60;
7	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
8	
9	const BASE_PREMIUM: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	export function processScenario(scenario: any): any {
19	  const step = scenario.steps[0];
20	  let basePremium = 0;
21	  const typeCounts: Record<string, number> = {};
22	  for (const item of step.items) {
23	    typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
24	  }
25	  for (const [type, count] of Object.entries(typeCounts)) {
26	    const isComponentType = COMPONENT_TYPES.has(type);
27	    const formsBlockOf3 = count === 3 && isComponentType;
28	    if (formsBlockOf3) {
29	      basePremium += BLOCK_OF_3_PRICE;
30	    } else {
31	      basePremium += count * BASE_PREMIUM[type];
32	    }
33	  }
34	  let curseSurcharge = 0;
35	  let highEnchantmentSurcharge = 0;
36	  for (const item of step.items) {
37	    if (item.cursed) {
38	      curseSurcharge += BASE_PREMIUM[item.type] * CURSE_SURCHARGE_RATE;
39	    }
40	    if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
41	      highEnchantmentSurcharge += BASE_PREMIUM[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE;
42	    }
43	  }
44	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
45	  const premium = basePremium + curseSurcharge + highEnchantmentSurcharge + firstInsuranceSurcharge + PROCESSING_FEE;
46	  return { results: [{ premium }] };
47	}
